   769→	'!==': (left, right) => left !== right,
   770→	'<': (left, right) => left < right,
   771→	'<=': (left, right) => left <= right,
   772→	'>': (left, right) => left > right,
   773→	'>=': (left, right) => left >= right,
   774→	'==': (left, right) => left == right,
   775→	'===': (left, right) => left === right,
   776→	in: (left, right) => left in right,
   777→	instanceof: (left, right) => left instanceof right,
   778→	'%': (left, right) => left % right,
   779→	'&': (left, right) => left & right,
   780→	'*': (left, right) => left * right,
   781→	'**': (left, right) => left ** right,
   782→	'+': (left, right) => left + right,
   783→	'-': (left, right) => left - right,
   784→	'/': (left, right) => left / right,
   785→	'<<': (left, right) => left << right,
