   964→		},
   965→
   966→		// references
   967→		Identifier(node, { path, state }) {
   968→			const parent = path.at(-1);
   969→			if (
   970→				parent &&
   971→				is_reference(node, /** @type {Node} */ (parent)) &&
   972→				// TSTypeAnnotation, TSInterfaceDeclaration etc - these are normally already filtered out,
   973→				// but for the migration they aren't, so we need to filter them out here
   974→				// TODO -> once migration script is gone we can remove this check
