  1001→
  1002→		SvelteFragment,
  1003→		SlotElement: SvelteFragment,
  1004→		SvelteElement: SvelteFragment,
  1005→		RegularElement: SvelteFragment,
  1006→
  1007→		LetDirective(node, context) {
