  1029→				scope.reference(id, [context.path[context.path.length - 1], node]);
  1030→				bindings.push(binding);
  1031→			}
  1032→		},
  1033→
  1034→		Component: (node, context) => {
  1035→			context.state.scope.reference(b.id(node.name), context.path);
  1036→			Component(node, context);
  1037→		},
  1038→		SvelteSelf: Component,
  1039→		SvelteComponent: Component,
  1040→
  1041→		// updates
  1042→		AssignmentExpression(node, { state, next }) {
  1043→			updates.push([state.scope, node.left]);
  1044→			next();
  1045→		},
  1046→
  1047→		UpdateExpression(node, { state, next }) {
  1048→			updates.push([state.scope, /** @type {Identifier | MemberExpression} */ (node.argument)]);
  1049→			next();
  1050→		},
  1051→
  1052→		ImportDeclaration(node, { state }) {
  1053→			for (const specifier of node.specifiers) {
  1054→				state.scope.declare(specifier.local, 'normal', 'import', node);
  1055→			}
  1056→		},
  1057→
  1058→		FunctionExpression(node, { state, next }) {
  1059→			const scope = state.scope.child();
  1060→			scopes.set(node, scope);
  1061→
  1062→			if (node.id) scope.declare(node.id, 'normal', 'function');
  1063→
  1064→			add_params(scope, node.params);
  1065→			next({ scope });
  1066→		},
  1067→
  1068→		FunctionDeclaration(node, { state, next }) {
  1069→			if (node.id) state.scope.declare(node.id, 'normal', 'function', node);
  1070→
  1071→			const scope = state.scope.child();
  1072→			scopes.set(node, scope);
  1073→
  1074→			add_params(scope, node.params);
  1075→			next({ scope });
  1076→		},
  1077→
  1078→		ArrowFunctionExpression(node, { state, next }) {
  1079→			const scope = state.scope.child();
  1080→			scopes.set(node, scope);
  1081→
  1082→			add_params(scope, node.params);
  1083→			next({ scope });
  1084→		},
  1085→
  1086→		ForStatement: create_block_scope,
  1087→		ForInStatement: create_block_scope,
  1088→		ForOfStatement: create_block_scope,
  1089→		SwitchStatement: create_block_scope,
  1090→		BlockStatement(node, context) {
  1091→			const parent = context.path.at(-1);
  1092→			if (
  1093→				parent?.type === 'FunctionDeclaration' ||
  1094→				parent?.type === 'FunctionExpression' ||
  1095→				parent?.type === 'ArrowFunctionExpression'
  1096→			) {
  1097→				// We already created a new scope for the function
  1098→				context.next();
  1099→			} else {
  1100→				create_block_scope(node, context);
  1101→			}
  1102→		},
  1103→
  1104→		ClassDeclaration(node, { state, next }) {
  1105→			if (node.id) state.scope.declare(node.id, 'normal', 'let', node);
  1106→			next();
  1107→		},
  1108→
  1109→		VariableDeclaration(node, { state, path, next }) {
  1110→			const is_parent_const_tag = path.at(-1)?.type === 'ConstTag';
  1111→			for (const declarator of node.declarations) {
  1112→				/** @type {Binding[]} */
  1113→				const bindings = [];
  1114→
  1115→				state.scope.declarators.set(declarator, bindings);
  1116→
  1117→				for (const id of extract_identifiers(declarator.id)) {
  1118→					const binding = state.scope.declare(
  1119→						id,
  1120→						is_parent_const_tag ? 'template' : 'normal',
  1121→						node.kind,
  1122→						declarator.init
