  1197→				expression: create_expression_metadata(),
  1198→				keyed: false,
  1199→				contains_group_binding: false,
  1200→				index: scope.root.unique('$$index'),
  1201→				declarations: scope.declarations,
  1202→				is_controlled: false,
  1203→				// filled in during analysis
  1204→				transitive_deps: new Set()
  1205→			};
  1206→		},
  1207→
  1208→		AwaitBlock(node, context) {
  1209→			context.visit(node.expression);
  1210→
  1211→			if (node.pending) {
  1212→				context.visit(node.pending);
  1213→			}
  1214→
  1215→			if (node.then) {
  1216→				context.visit(node.then);
  1217→				if (node.value) {
  1218→					const then_scope = /** @type {Scope} */ (scopes.get(node.then));
  1219→					const value_scope = context.state.scope.child();
  1220→					scopes.set(node.value, value_scope);
  1221→					context.visit(node.value, { scope: value_scope });
