  1223→						then_scope.declare(id, 'template', 'const');
  1224→						value_scope.declare(id, 'normal', 'const');
  1225→					}
  1226→				}
  1227→			}
  1228→
  1229→			if (node.catch) {
  1230→				context.visit(node.catch);
  1231→				if (node.error) {
  1232→					const catch_scope = /** @type {Scope} */ (scopes.get(node.catch));
  1233→					const error_scope = context.state.scope.child();
  1234→					scopes.set(node.error, error_scope);
  1235→					context.visit(node.error, { scope: error_scope });
  1236→					for (const id of extract_identifiers(node.error)) {
  1237→						catch_scope.declare(id, 'template', 'const');
  1238→						error_scope.declare(id, 'normal', 'const');
  1239→					}
  1240→				}
  1241→			}
  1242→		},
  1243→
  1244→		SnippetBlock(node, context) {
  1245→			const state = context.state;
  1246→			let scope = state.scope;
  1247→
  1248→			scope.declare(node.expression, 'normal', 'function', node);
  1249→
  1250→			const child_scope = state.scope.child();
  1251→			scopes.set(node, child_scope);
  1252→
  1253→			for (const param of node.parameters) {
  1254→				for (const id of extract_identifiers(param)) {
  1255→					child_scope.declare(id, 'snippet', 'let');
  1256→				}
  1257→			}
  1258→
  1259→			context.next({ scope: child_scope });
  1260→		},
  1261→
  1262→		Fragment: (node, context) => {
  1263→			const scope = context.state.scope.child(node.metadata.transparent);
  1264→			scopes.set(node, scope);
  1265→			context.next({ scope });
  1266→		},
  1267→
  1268→		BindDirective(node, context) {
  1269→			updates.push([
  1270→				context.state.scope,
  1271→				/** @type {Identifier | MemberExpression} */ (node.expression)
  1272→			]);
  1273→			context.next();
  1274→		},
  1275→
  1276→		TransitionDirective: SvelteDirective,
  1277→		AnimateDirective: SvelteDirective,
  1278→		UseDirective: SvelteDirective,
  1279→		// using it's own function instead of `SvelteDirective` because
  1280→		// StyleDirective doesn't have expressions and are generally already
  1281→		// handled by `Identifier`. This is the special case for the shorthand
  1282→		// eg <button style:height /> where the variable has the same name of
  1283→		// the css property
  1284→		StyleDirective(node, { path, state, next }) {
  1285→			if (node.value === true) {
  1286→				state.scope.reference(b.id(node.name), path.concat(node));
  1287→			}
  1288→			next();
  1289→		}
  1290→
  1291→		// TODO others
  1292→	});
