  1297→
  1298→		scope.declare(id, 'legacy_reactive', 'let');
  1299→	}
  1300→
  1301→	// we do this after the fact, so that we don't need to worry
  1302→	// about encountering references before their declarations
  1303→	for (const [scope, { node, path }] of references) {
  1304→		scope.reference(node, path);
  1305→	}
  1306→
  1307→	for (const [scope, node] of updates) {
  1308→		for (const expression of unwrap_pattern(node)) {
  1309→			const left = object(expression);
  1310→			const binding = left && scope.get(left.name);
  1311→
  1312→			if (binding !== null && left !== binding.node) {
  1313→				if (left === expression) {
  1314→					binding.reassigned = true;
  1315→				} else {
  1316→					binding.mutated = true;
  1317→				}
  1318→			}
  1319→		}
  1320→	}
  1321→
  1322→	return {
  1323→		has_await,
  1324→		scope,
  1325→		scopes
  1326→	};
  1327→}
  1328→
  1329→/**
  1330→ * @template {{ scope: Scope, scopes: Map<AST.SvelteNode, Scope> }} State
  1331→ * @param {AST.SvelteNode} node
  1332→ * @param {Context<AST.SvelteNode, State>} context
  1333→ */
  1334→export function set_scope(node, { next, state }) {
  1335→	const scope = state.scopes.get(node);
  1336→	next(scope !== undefined && scope !== state.scope ? { ...state, scope } : state);
  1337→}
  1338→
  1339→/**
  1340→ * Returns the name of the rune if the given expression is a `CallExpression` using a rune.
  1341→ * @param {Node | null | undefined} node
  1342→ * @param {Scope} scope
  1343→ */
  1344→export function get_rune(node, scope) {
  1345→	if (!node) return null;
  1346→	if (node.type !== 'CallExpression') return null;
  1347→
  1348→	const keypath = get_global_keypath(node.callee, scope);
  1349→
  1350→	if (!keypath || !is_rune(keypath)) return null;
  1351→	return keypath;
  1352→}
  1353→
  1354→/**
  1355→ * Returns the name of the rune if the given expression is a `CallExpression` using a rune.
  1356→ * @param {Expression | Super} node
  1357→ * @param {Scope} scope
  1358→ */
  1359→function get_global_keypath(node, scope) {
  1360→	let n = node;
  1361→
  1362→	let joined = '';
  1363→
  1364→	while (n.type === 'MemberExpression') {
  1365→		if (n.computed) return null;
  1366→		if (n.property.type !== 'Identifier') return null;
  1367→		joined = '.' + n.property.name + joined;
  1368→		n = n.object;
  1369→	}
  1370→
  1371→	if (n.type === 'CallExpression' && n.callee.type === 'Identifier') {
  1372→		joined = '()' + joined;
  1373→		n = n.callee;
  1374→	}
  1375→
  1376→	if (n.type !== 'Identifier') return null;
  1377→
  1378→	const binding = scope.get(n.name);
  1379→	if (binding !== null) return null; // rune name, but references a variable or store
  1380→
  1381→	return n.name + joined;
  1382→}
