     1→/** @import { AssignmentExpression, Expression, Identifier, MemberExpression, SequenceExpression, Literal, Super, UpdateExpression, ExpressionStatement } from 'estree' */
     2→/** @import { AST, ExpressionMetadata } from '#compiler' */
     3→/** @import { ComponentClientTransformState, ComponentContext, Context } from '../../types' */
