import { compile } from './packages/svelte/src/compiler/index.js';

const source = `<script>
	experimental = { async: true }

	let value = $state('test');

	async function getValue() {
		await new Promise(resolve => setTimeout(resolve, 100));
		return 'async value';
	}
</script>

{#snippet testSnippet()}
	<!-- This should work but fails in v5.38.3 -->
	{@const awaitedValue = await getValue()}
	<p>{awaitedValue}</p>

	<!-- Direct await without const declaration - this is the main bug -->
	<p>{await Promise.resolve(value)}</p>
{/snippet}

{@render testSnippet()}`;

try {
	const result = compile(source, {
		generate: 'client',
		experimental: { async: true }
	});

	console.log('✅ Compilation successful!');
	console.log('Generated code contains async function:', result.js.code.includes('async'));

	// Check if the snippet function is properly marked as async
	if (result.js.code.includes('function(\n$$anchor\n) {')) {
		console.log('❌ Snippet function is not async - BUG PRESENT');
	} else if (result.js.code.includes('async function(\n$$anchor\n) {')) {
		console.log('✅ Snippet function is async - BUG FIXED');
	} else {
		console.log('⚠️ Unable to determine async status of snippet function');
	}

} catch (error) {
	console.error('❌ Compilation failed:', error.message);
}

