import { compile } from './packages/svelte/src/compiler/index.js';

const source = `<script>
	experimental = { async: true }

	async function getValue() {
		await new Promise(resolve => setTimeout(resolve, 100));
		return 'async value';
	}
</script>

{#snippet testSnippet()}
	<!-- Direct await without const declaration - this is the main bug -->
	<p>{await getValue()}</p>
{/snippet}

{@render testSnippet()}`;

try {
	const result = compile(source, {
		generate: 'client',
		experimental: { async: true }
	});

	console.log('✅ Compilation successful!');

	// Search for the snippet function pattern more specifically
	const snippetFunctionMatch = result.js.code.match(/function\s*\(([^\)]+)\)\s*{/);
	const asyncSnippetFunctionMatch = result.js.code.match(/async\s+function\s*\(([^\)]+)\)\s*{/);

	if (snippetFunctionMatch) {
		console.log('Standard function found:', snippetFunctionMatch[0]);
	}

	if (asyncSnippetFunctionMatch) {
		console.log('Async function found:', asyncSnippetFunctionMatch[0]);
	}

	// Check specifically for snippet-related async indicators
	const snippetCode = result.js.code.toLowerCase();

	console.log('Contains snippet async keyword:', snippetCode.includes('async'));
	console.log('Contains ArrowFunctionExpression with async:', snippetCode.includes('arrowfunctionexpression') && snippetCode.includes('async'));

	// Look for specific patterns in the compiled output
	if (snippetCode.includes('testSnippet') && snippetCode.includes('async')) {
		console.log('✅ Bug appears to be FIXED - snippet is async');
	} else if (snippetCode.includes('testSnippet') && !snippetCode.includes('async')) {
		console.log('❌ Bug is NOT FIXED - snippet is not async');
	} else {
		console.log('⚠️ Could not determine snippet function status');
	}

} catch (error) {
	console.error('❌ Compilation failed:', error.message);
}

